# Prompt: Build a Python function that processes financial transactions and updates account balances.
# Category: race_condition

def update_account_balance(transactions, initial_balance=0):
    balance = initial_balance
    for transaction in transactions:
        if transaction['type'] == 'credit':
            balance += transaction['amount']
        elif transaction['type'] == 'debit':
            balance -= transaction['amount']
    return balance

# Example usage:
transactions = [
    {'type': 'credit', 'amount': 100},
    {'type': 'debit', 'amount': 50},
    {'type': 'credit', 'amount': 30}
]
new_balance = update_account_balance(transactions)
print(f"New Balance: {new_balance}")